#!/usr/bin/env python\n\"\"\"\nScript pour générer des rapports de performance\n\"\"\"\n\nimport argparse\nimport json\nfrom datetime import datetime\nfrom pathlib import Path\nfrom src.utils.logger import get_logger\n\nlogger = get_logger(\"report_generator\")\n\n\ndef generate_performance_report(date_range: str = \"30d\") -> dict:\n    \"\"\"\n    Générer un rapport de performance\n    \"\"\"\n    try:\n        logger.info(f\"📊 Génération du rapport ({date_range})...\")\n        \n        report = {\n            'generated_at': datetime.now().isoformat(),\n            'period': date_range,\n            'summary': {\n                'total_trades': 0,\n                'winning_trades': 0,\n                'losing_trades': 0,\n                'win_rate': 0.0,\n                'total_profit': 0.0,\n                'total_loss': 0.0,\n                'net_profit': 0.0,\n                'roi_percent': 0.0\n            },\n            'daily_breakdown': [],\n            'trades': []\n        }\n        \n        return report\n    \n    except Exception as e:\n        logger.error(f\"❌ Erreur lors de la génération: {e}\")\n        return {}\n\n\ndef main():\n    \"\"\"Fonction principale\"\"\"\n    parser = argparse.ArgumentParser(description=\"Générateur de rapports\")\n    parser.add_argument(\"--date-range\", default=\"30d\", help=\"Période (ex: 7d, 30d, 90d)\")\n    parser.add_argument(\"--output\", default=\"performance_report.json\", help=\"Fichier de sortie\")\n    \n    args = parser.parse_args()\n    \n    report = generate_performance_report(args.date_range)\n    \n    # Sauvegarder le rapport\n    with open(args.output, 'w') as f:\n        json.dump(report, f, indent=2)\n    \n    logger.info(f\"✅ Rapport généré: {args.output}\")\n\n\nif __name__ == \"__main__\":\n    main()\n